def gen(rng, size):
    n = max(1, min(size, 12))
    edges = []
    for u in range(n):
        for v in range(u + 1, n):
            if rng.random() < 0.35:
                edges.append([u, v])
    score = [rng.randrange(1, 100001) for _ in range(n)]
    return [n, edges, score]

