import itertools
class Solution:
    def maxProfit(self, n, edges, score):
        es = [(u, v) for u, v in edges]
        best = None
        for perm in itertools.permutations(range(n)):
            pos = {node: i + 1 for i, node in enumerate(perm)}
            if all(pos[u] < pos[v] for u, v in es):
                tot = sum(score[node] * pos[node] for node in range(n))
                if best is None or tot > best:
                    best = tot
        return best

