class Solution:
    def maxProfit(self, n, edges, score):
        pred = [0] * n
        for u, v in edges:
            pred[v] |= (1 << u)
        NEG = float('-inf')
        dp = [NEG] * (1 << n)
        dp[0] = 0
        for mask in range(1 << n):
            if dp[mask] == NEG:
                continue
            pos = bin(mask).count('1') + 1
            for v in range(n):
                if mask & (1 << v):
                    continue
                if pred[v] & mask == pred[v]:
                    nm = mask | (1 << v)
                    cand = dp[mask] + score[v] * pos
                    if cand > dp[nm]:
                        dp[nm] = cand
        return dp[(1 << n) - 1]

