var maxProfit = function(n, edges, score) {
    const pred = new Array(n).fill(0);
    for (const [u, v] of edges) pred[v] |= (1 << u);
    const NEG = -Infinity;
    const size = 1 << n;
    const dp = new Array(size).fill(NEG);
    dp[0] = 0;
    for (let mask = 0; mask < size; mask++) {
        if (dp[mask] === NEG) continue;
        let bits = 0, m = mask;
        while (m) { bits += m & 1; m >>= 1; }
        const pos = bits + 1;
        for (let v = 0; v < n; v++) {
            if (mask & (1 << v)) continue;
            if ((pred[v] & mask) === pred[v]) {
                const nm = mask | (1 << v);
                const cand = dp[mask] + score[v] * pos;
                if (cand > dp[nm]) dp[nm] = cand;
            }
        }
    }
    return dp[size - 1];
};
